'use client';

import { useAppointments } from '../../hooks/useAppointments';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '../../components/ui/Table';
import Card from '../../components/ui/Card';
import Badge from '../../components/ui/Badge';
import { Calendar, Clock, LayoutDashboard, ChevronRight, CheckCircle2 } from 'lucide-react';
import Button from '../../components/ui/Button';

export default function ClinicianPage() {
  const { data: appointments, isLoading, error } = useAppointments();

  const getStatusBadge = (status: string) => {
    switch (status?.toLowerCase()) {
      case 'completed': return 'success';
      case 'scheduled': return 'primary';
      case 'cancelled': return 'danger';
      default: return 'gray';
    }
  };

  return (
    <div className="space-y-8 animate-fade-in">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-3xl font-bold tracking-tight text-gray-900 flex items-center gap-3">
            <LayoutDashboard className="w-8 h-8 text-primary" />
            Clinician Dashboard
          </h1>
          <p className="text-gray-500 mt-2">Overview of today's appointments and clinic metrics.</p>
        </div>
        <div className="flex flex-wrap items-center gap-3">
          <Button variant="secondary">Download Report</Button>
          <Button>View All Patients</Button>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mt-6">
        <Card className="p-6 bg-gradient-to-br from-primary/10 to-transparent border-primary/20 relative overflow-hidden group">
          <div className="absolute top-0 right-0 p-4 opacity-20 transition-transform group-hover:scale-110">
            <Calendar className="w-16 h-16 text-primary" />
          </div>
          <h3 className="text-sm font-medium text-gray-500 mb-2 relative z-10">Today's Appointments</h3>
          <p className="text-4xl font-bold text-gray-900 relative z-10">{appointments?.length || 0}</p>
        </Card>
        <Card className="p-6 bg-gradient-to-br from-warning/10 to-transparent border-warning/20 relative overflow-hidden group">
          <div className="absolute top-0 right-0 p-4 opacity-20 transition-transform group-hover:scale-110">
            <Clock className="w-16 h-16 text-warning" />
          </div>
          <h3 className="text-sm font-medium text-gray-500 mb-2 relative z-10">Pending Triage</h3>
          <p className="text-4xl font-bold text-gray-900 relative z-10">4</p>
        </Card>
        <Card className="p-6 bg-gradient-to-br from-success/10 to-transparent border-success/20 relative overflow-hidden group">
          <div className="absolute top-0 right-0 p-4 opacity-20 transition-transform group-hover:scale-110">
            <CheckCircle2 className="w-16 h-16 text-success" />
          </div>
          <h3 className="text-sm font-medium text-gray-500 mb-2 relative z-10">Completed</h3>
          <p className="text-4xl font-bold text-gray-900 relative z-10">
            {appointments?.filter((a: any) => a.status === 'completed').length || 0}
          </p>
        </Card>
      </div>

      <Card className="p-0 overflow-hidden border-gray-200/60 shadow-sm mt-8">
        <div className="p-6 border-b flex flex-col md:flex-row items-center justify-between gap-4 bg-gray-50/30">
          <div>
            <h2 className="text-xl font-semibold text-gray-900">Recent Appointments</h2>
            <p className="text-sm text-gray-500 mt-1">Manage and view details of upcoming scheduled patients.</p>
          </div>
          <div className="text-sm text-primary font-medium cursor-pointer hover:text-primary-600 transition-colors flex items-center gap-1 group">
            View full calendar <ChevronRight className="w-4 h-4 transition-transform group-hover:translate-x-1" />
          </div>
        </div>

        {isLoading && (
          <div className="py-16 flex flex-col justify-center items-center gap-4">
            <div className="w-8 h-8 border-4 border-primary/30 border-t-primary rounded-full animate-spin"></div>
            <p className="text-sm text-gray-500">Loading appointments data...</p>
          </div>
        )}

        {error && (
          <div className="p-6">
            <p className="text-danger bg-danger/10 p-4 rounded-lg border border-danger/20 font-medium">Failed to load appointments from server. Please try again later.</p>
          </div>
        )}

        {appointments && appointments.length > 0 && (
          <Table>
            <TableHeader>
              <TableRow className="bg-gray-50 hover:bg-gray-50">
                <TableHead className="font-semibold text-gray-600">Patient Name</TableHead>
                <TableHead className="font-semibold text-gray-600">Provider</TableHead>
                <TableHead className="font-semibold text-gray-600">Date & Time</TableHead>
                <TableHead className="font-semibold text-gray-600">Status</TableHead>
                <TableHead className="text-right font-semibold text-gray-600">Actions</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {appointments.map((appt: any, idx: number) => {
                const date = new Date(appt.time);
                return (
                  <TableRow key={idx} className="group">
                    <TableCell className="font-medium text-gray-900">{appt.patient}</TableCell>
                    <TableCell className="text-gray-600">
                      <div className="flex items-center gap-2">
                        <div className="w-6 h-6 rounded-full bg-primary/10 text-primary flex items-center justify-center text-xs font-bold shrink-0">
                          {appt.provider ? appt.provider.charAt(3) : '?'}
                        </div>
                        {appt.provider || 'Unknown Provider'}
                      </div>
                    </TableCell>
                    <TableCell>
                      <div className="flex items-center gap-3 text-sm text-gray-600">
                        <span className="flex items-center gap-1.5 bg-gray-100 px-2 py-1 rounded-md">
                          <Calendar className="w-3.5 h-3.5 text-gray-400" />
                          {date.toLocaleDateString()}
                        </span>
                        <span className="flex items-center gap-1.5 bg-gray-100 px-2 py-1 rounded-md">
                          <Clock className="w-3.5 h-3.5 text-gray-400" />
                          {date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                        </span>
                      </div>
                    </TableCell>
                    <TableCell>
                      <Badge variant={getStatusBadge(appt.status)} className="capitalize">
                        {appt.status}
                      </Badge>
                    </TableCell>
                    <TableCell className="text-right">
                      <Button variant="ghost" className="text-sm opacity-0 group-hover:opacity-100 transition-opacity translate-x-4 group-hover:translate-x-0">
                        Details
                      </Button>
                    </TableCell>
                  </TableRow>
                );
              })}
            </TableBody>
          </Table>
        )}

        {appointments && appointments.length === 0 && (
          <div className="py-16 text-center text-gray-500">
            <Calendar className="w-12 h-12 text-gray-300 mx-auto mb-3" />
            <p className="text-lg font-medium text-gray-900">No appointments found</p>
            <p className="mt-1">There are no appointments scheduled for today.</p>
          </div>
        )}
      </Card>
    </div>
  );
}

'use client';

import { useState } from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import * as z from 'zod';
import { AlertTriangle, CheckCircle2, FileText, HeartPulse } from 'lucide-react';
import Card from '../../components/ui/Card';
import Button from '../../components/ui/Button';
import Alert from '../../components/ui/Alert';
import Badge from '../../components/ui/Badge';
import { useTriage } from '../../hooks/useTriage';

const triageSchema = z.object({
  symptoms: z.string().min(5, "Please describe the symptoms in more detail (at least 5 characters)."),
});

type TriageFormValues = z.infer<typeof triageSchema>;

export default function TriagePage() {
  const { mutate: runTriage, data: triageResult, isPending, error } = useTriage();

  const {
    register,
    handleSubmit,
    formState: { errors },
  } = useForm<TriageFormValues>({
    resolver: zodResolver(triageSchema),
  });

  const onSubmit = (data: TriageFormValues) => {
    runTriage({ symptoms: data.symptoms });
  };

  const getUrgencyColor = (urgency: string) => {
    switch (urgency?.toLowerCase()) {
      case 'high': return 'danger';
      case 'medium': return 'warning';
      case 'low': return 'success';
      default: return 'primary';
    }
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8 animate-fade-in">
      <div className="text-center space-y-2">
        <div className="inline-flex items-center justify-center p-3 bg-primary/10 rounded-full mb-4">
          <HeartPulse className="w-8 h-8 text-primary" />
        </div>
        <h1 className="text-3xl font-bold tracking-tight text-gray-900">AI-Assisted Triage</h1>
        <p className="text-gray-500 max-w-2xl mx-auto">
          Enter the patient's symptoms to receive an AI-generated preliminary assessment, including urgency level and possible conditions.
        </p>
      </div>

      <Card className="p-6 md:p-8 border-t-4 border-t-primary">
        <form onSubmit={handleSubmit(onSubmit)} className="space-y-6">
          <div className="space-y-2">
            <label className="text-sm font-medium text-gray-700">Patient Symptoms</label>
            <div className="relative">
              <textarea
                {...register('symptoms')}
                rows={4}
                placeholder="Describe symptoms here... e.g., 'Patient complains of severe chest pain...'"
                className={`w-full px-4 py-3 rounded-lg border bg-gray-50/50 transition-colors duration-200 outline-none
                  ${errors.symptoms
                    ? 'border-danger focus:ring-2 focus:ring-danger/20'
                    : 'border-gray-200 focus:border-primary focus:ring-2 focus:ring-primary/20 hover:border-gray-300'
                  }`}
              />
            </div>
            {errors.symptoms && (
              <p className="text-sm text-danger flex items-center gap-1 mt-1">
                <AlertTriangle className="w-4 h-4" /> {errors.symptoms.message}
              </p>
            )}
          </div>

          <div className="flex justify-end">
            <Button type="submit" disabled={isPending} className="px-8 flex items-center gap-2">
              {isPending && <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />}
              {isPending ? 'Analyzing Symptoms...' : 'Analyze Symptoms'}
            </Button>
          </div>
        </form>
      </Card>

      {error && (
        <Alert type="error">
          There was an error while trying to generate the triage assessment. Please try again.
        </Alert>
      )}

      {triageResult && (
        <div className="space-y-6 animate-slide-up">
          <h2 className="text-xl font-semibold border-b pb-2 flex items-center gap-2">
            <FileText className="w-5 h-5 text-primary" /> Assessment Report
          </h2>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <Card className="p-6 col-span-1 border-l-4 overflow-hidden relative" style={{ borderLeftColor: `var(--color-${getUrgencyColor(triageResult.urgency)})` }}>
              <div className="absolute top-0 right-0 p-4 opacity-10">
                <AlertTriangle className="w-16 h-16" style={{ color: `var(--color-${getUrgencyColor(triageResult.urgency)})` }} />
              </div>
              <h3 className="text-sm font-medium text-gray-500 uppercase tracking-wider mb-2 relative z-10">Urgency Level</h3>
              <div className="flex flex-col gap-2 relative z-10">
                <span className="text-3xl font-bold text-gray-900">{triageResult.urgency}</span>
                <div className="inline-block">
                  <Badge variant={getUrgencyColor(triageResult.urgency)}>
                    {Math.round(triageResult.confidence * 100)}% Confidence
                  </Badge>
                </div>
              </div>
            </Card>

            <Card className="p-6 col-span-1 md:col-span-2">
              <h3 className="text-sm font-medium text-gray-500 uppercase tracking-wider mb-2">Clinical Explanation</h3>
              <p className="text-gray-800 leading-relaxed">{triageResult.explanation}</p>
            </Card>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <Card className="p-6">
              <h3 className="text-sm font-medium text-gray-500 uppercase tracking-wider mb-4">Possible Conditions</h3>
              <div className="space-y-4">
                {triageResult.conditions?.map((c: any, index: number) => (
                  <div key={index}>
                    <div className="flex justify-between mb-1">
                      <span className="font-medium text-gray-900">{c.name}</span>
                      <span className="text-sm text-gray-500">{Math.round(c.probability * 100)}%</span>
                    </div>
                    <div className="w-full bg-gray-100 rounded-full h-2 overflow-hidden">
                      <div
                        className={`h-full rounded-full transition-all duration-1000 ${index === 0 ? 'bg-primary' : 'bg-gray-400'}`}
                        style={{ width: `${c.probability * 100}%` }}
                      ></div>
                    </div>
                  </div>
                ))}
              </div>
            </Card>

            <Card className="p-6 bg-primary/5 border border-primary/10">
              <h3 className="text-sm font-medium text-primary uppercase tracking-wider mb-4 flex items-center gap-2">
                <CheckCircle2 className="w-4 h-4" /> Recommended Next Steps
              </h3>
              <ul className="space-y-3">
                {triageResult.recommended?.map((step: string, i: number) => (
                  <li key={i} className="flex items-start gap-3">
                    <div className="w-1.5 h-1.5 rounded-full bg-primary mt-2 flex-shrink-0" />
                    <span className="text-gray-800 leading-relaxed">{step}</span>
                  </li>
                ))}
              </ul>
            </Card>
          </div>
        </div>
      )}
    </div>
  );
}
